        self.current_piece.x = self.grid_width // 2 - 2
        self.current_piece.y = 0
        if self.check_collision(self.current_piece, 0, 0):
            self.game_over = True
            return False
        return True

    def check_collision(self, piece, offset_x, offset_y):
        for y in range(piece.get_height()):
            for x in range(piece.get_width()):
                if piece.shape[y][x] != '.':
                    grid_x = piece.x + x + offset_x
                    grid_y = piece.y + y + offset_y

                    if grid_x < 0 or grid_x >= self.grid_width or grid_y >= self.grid_height:
