            original_shape = [list(row) for row in self.current_piece.shape]
            self.current_piece.rotate()
            if self.check_collision(self.current_piece, 0, 0):
                self.current_piece.shape = original_shape

    def lock_piece(self):
        if not self.current_piece:
            return
        for y in range(self.current_piece.get_height()):
            for x in range(self.current_piece.get_width()):
                if self.current_piece.shape[y][x] != '.':
