            color = color_for_tetromino(piece.color)
            for y in range(piece.get_height()):
                for x in range(piece.get_width()):
                    if piece.shape[y][x] != '.':
                        rect = pygame.Rect((piece.x + x) * CELL_SIZE, (piece.y + y) * CELL_SIZE, CELL_SIZE, CELL_SIZE)
                        pygame.draw.rect(self.screen, color, rect)
                        pygame.draw.rect(self.screen, GRAY, rect, 1)

    def draw_next_piece(self):
        text_surface = self.font.render("Next Piece:", True, WHITE)
        self.screen.blit(text_surface, (PREVIEW_X, PREVIEW_Y - 25))

        piece = self.next_piece
        if piece:
            color = color_for_tetromino(piece.color)
            start_x = PREVIEW_X + (PREVIEW_WIDTH * CELL_SIZE - piece.get_width() * CELL_SIZE) // 2
            start_y = PREVIEW_Y + (PREVIEW_HEIGHT * CELL_SIZE - piece.get_height() * CELL_SIZE) // 2

            for y in range(piece.get_height()):
                for x in range(piece.get_width()):
                    if piece.shape[y][x] != '.':
                        rect = pygame.Rect(start_x + x * CELL_SIZE, start_y + y * CELL_SIZE, CELL_SIZE, CELL_SIZE)
                        pygame.draw.rect(self.screen, color, rect)
                        pygame.draw.rect(self.screen, GRAY, rect, 1)

    def draw_score(self):
        text_surface = self.font.render(f"Score: {self.score}", True, WHITE)
        self.screen.blit(text_surface, (SCORE_X, SCORE_Y))

    def draw_game_over(self):
        text_surface = self.font.render("Game Over!", True, RED)
        text_rect = text_surface.get_rect(center=(SCREEN_WIDTH // 2, SCREEN_HEIGHT // 2))
        self.screen.blit(text_surface, text_rect)

    def handle_input(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.running = False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    self.move_piece_sideways(-1)
                elif event.key == pygame.K_RIGHT:
                    self.move_piece_sideways(1)
                elif event.key == pygame.K_DOWN:
                    self.move_piece_down()
                elif event.key == pygame.K_UP:
                    self.rotate_piece()
                elif event.key == pygame.K_SPACE:
                    while self.move_piece_down():
                        pass
                    self.lock_piece()
                elif event.key == pygame.K_d:
                    self.debug = not self.debug

    def update(self):
        if not self.game_over:
            time_passed_seconds = self.clock.tick(60) / 1000.0
            self.time_since_fall += time_passed_seconds
            if self.time_since_fall > (1 / self.fall_speed):
                self.time_since_fall -= (1 / self.fall_speed)
                self.move_piece_down()

    def render(self):
        self.screen.fill(BLACK)
        self.draw_grid()
        self.draw_piece(self.current_piece)
        self.draw_next_piece()
        self.draw_score()
        if self.game_over:
            self.draw_game_over()
        pygame.display.flip()

    def run(self):
        while self.running:
            self.handle_input()
            self.update()
            self.render()

        pygame.quit()

if __name__ == '__main__':
    game = Game(GRID_WIDTH, GRID_HEIGHT)
    game.run()
