            else:
                self.lock_piece()
                return False
        return False

    def rotate_piece(self):
        if self.current_piece:
            original_shape = [list(row) for row in self.current_piece.shape]
            self.current_piece.rotate()
            if self.check_collision(self.current_piece, 0, 0):
                self.current_piece.shape = original_shape

    def lock_piece(self):
        if not self.current_piece:
            return
        for y in range(self.current_piece.get_height()):
            for x in range(self.current_piece.get_width()):
                if self.current_piece.shape[y][x] != '.':
                    grid_x = self.current_piece.x + x
                    grid_y = self.current_piece.y + y
                    if 0 <= grid_x < self.grid_width and 0 <= grid_y < self.grid_height:
                        self.grid.lock_tetromino_block(grid_x, grid_y, self.current_piece.shape[y][x])
        self.current_piece = None
        lines_cleared = self.clear_lines()
        matches_cleared = self.clear_matches()

        if lines_cleared > 0 or matches_cleared:
            self.handle_gravity()
            chain_cleared = True
            while chain_cleared:
                chain_cleared = self.clear_matches()
                if chain_cleared:
                    self.chain_reaction_count += 1
                    self.handle_gravity()
                else:
                    self.chain_reaction_count = 0
        else:
            self.chain_reaction_count = 0
        self.spawn_new_piece()

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.grid_height):
            if all(self.grid.get_cell(x, y).state == CellState.LOCKED for x in range(self.grid_width)):
                lines_cleared += 1
                for x in range(self.grid_width):
                    self.grid.clear_cell(x, y)
        if lines_cleared > 0:
            line_clear_score = lines_cleared ** 2 * 100
            self.score += line_clear_score
            self.score += self.chain_reaction_count * line_clear_score // 2
        return lines_cleared

    def clear_matches(self):
        matches_cleared = False
        matches = []
        for y in range(self.grid_height):
            for x in range(self.grid_width):
                if self.grid.get_cell(x, y).state == CellState.LOCKED:
                    color = self.grid.get_cell(x, y).color
                    # Check horizontal match
                    if x > 0 and x < self.grid_width - 1 and \
                       self.grid.get_cell(x - 1, y).state == CellState.LOCKED and self.grid.get_cell(x + 1, y).state == CellState.LOCKED and \
                       self.grid.get_cell(x - 1, y).color == color and self.grid.get_cell(x + 1, y).color == color:
                        if (x-1,y) not in matches:
                            matches.append((x-1,y))
                        if (x,y) not in matches:
                            matches.append((x,y))
                        if (x+1,y) not in matches:
                            matches.append((x+1,y))
                        matches_cleared = True

                    # Check vertical match
                    if y > 0 and y < self.grid_height - 1 and \
                       self.grid.get_cell(x, y - 1).state == CellState.LOCKED and self.grid.get_cell(x, y + 1).state == CellState.LOCKED and \
                       self.grid.get_cell(x, y - 1).color == color and self.grid.get_cell(x, y + 1).color == color:
                        if (x,y-1) not in matches:
                            matches.append((x,y-1))
                        if (x,y) not in matches:
                            matches.append((x,y))
                        if (x,y+1) not in matches:
                            matches.append((x,y+1))
                        matches_cleared = True
        for x, y in matches:
            self.grid.clear_cell(x, y)
        if matches_cleared:
            match_score = len(matches) * 50
            self.score += match_score
            self.score += self.chain_reaction_count * match_score // 2
        return matches_cleared

    def handle_gravity(self):
        for x in range(self.grid_width):
            for y in range(self.grid_height - 1, -1, -1):
                if self.grid.get_cell(x, y).state == CellState.EMPTY:
                    for yy in range(y - 1, -1, -1):
                        if self.grid.get_cell(x, yy).state == CellState.LOCKED:
                            color = self.grid.get_cell(x, yy).color
                            self.grid.clear_cell(x, yy)
                            self.grid.set_cell(x, y, CellState.LOCKED, color)
                            break

    def draw_grid(self):
        for y in range(self.grid_height):
            for x in range(self.grid_width):
                cell = self.grid.get_cell(x, y)
                rect = pygame.Rect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE)
                pygame.draw.rect(self.screen, cell.color, rect)
                pygame.draw.rect(self.screen, GRAY, rect, 1)  # Grid lines

    def draw_piece(self, piece):
        if piece:
            color = color_for_tetromino(piece.color)
            for y in range(piece.get_height()):
                for x in range(piece.get_width()):
                    if piece.shape[y][x] != '.':
                        rect = pygame.Rect((piece.x + x) * CELL_SIZE, (piece.y + y) * CELL_SIZE, CELL_SIZE, CELL_SIZE)
                        pygame.draw.rect(self.screen, color, rect)
                        pygame.draw.rect(self.screen, GRAY, rect, 1)

    def draw_next_piece(self):
        text_surface = self.font.render("Next Piece:", True, WHITE)
        self.screen.blit(text_surface, (PREVIEW_X, PREVIEW_Y - 25))

        piece = self.next_piece
        if piece:
            color = color_for_tetromino(piece.color)
            start_x = PREVIEW_X + (PREVIEW_WIDTH * CELL_SIZE - piece.get_width() * CELL_SIZE) // 2
            start_y = PREVIEW_Y + (PREVIEW_HEIGHT * CELL_SIZE - piece.get_height() * CELL_SIZE) // 2

            for y in range(piece.get_height()):
                for x in range(piece.get_width()):
                    if piece.shape[y][x] != '.':
                        rect = pygame.Rect(start_x + x * CELL_SIZE, start_y + y * CELL_SIZE, CELL_SIZE, CELL_SIZE)
                        pygame.draw.rect(self.screen, color, rect)
                        pygame.draw.rect(self.screen, GRAY, rect, 1)

    def draw_score(self):
        text_surface = self.font.render(f"Score: {self.score}", True, WHITE)
        self.screen.blit(text_surface, (SCORE_X, SCORE_Y))

    def draw_game_over(self):
        text_surface = self.font.render("Game Over!", True, RED)
        text_rect = text_surface.get_rect(center=(SCREEN_WIDTH // 2, SCREEN_HEIGHT // 2))
        self.screen.blit(text_surface, text_rect)

    def handle_input(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.running = False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    self.move_piece_sideways(-1)
                elif event.key == pygame.K_RIGHT:
                    self.move_piece_sideways(1)
                elif event.key == pygame.K_DOWN:
                    self.move_piece_down()
                elif event.key == pygame.K_UP:
                    self.rotate_piece()
                elif event.key == pygame.K_SPACE:
                    while self.move_piece_down():
                        pass
                    self.lock_piece()
                elif event.key == pygame.K_d:
                    self.debug = not self.debug

    def update(self):
        if not self.game_over:
            time_passed_seconds = self.clock.tick(60) / 1000.0
            self.time_since_fall += time_passed_seconds
            if self.time_since_fall > (1 / self.fall_speed):
                self.time_since_fall -= (1 / self.fall_speed)
                self.move_piece_down()

    def render(self):
        self.screen.fill(BLACK)
        self.draw_grid()
        self.draw_piece(self.current_piece)
        self.draw_next_piece()
        self.draw_score()
        if self.game_over:
            self.draw_game_over()
        pygame.display.flip()

    def run(self):
        while self.running:
            self.handle_input()
            self.update()
            self.render()

        pygame.quit()

if __name__ == '__main__':
    game = Game(GRID_WIDTH, GRID_HEIGHT)
    game.run()
